mapper.select:
select l.id as id, l.date as date, l.start_time as startTime, l.end_time as endTime, l.title as title, l.teach_type as listenType, ls.sign_state as signState, ls.dec_lesson_count as decLessonCount, s.name as teacher, c.name as className, cr.name as classroomName from lesson as l join lesson_student as ls on l.id = ls.lesson_id and ls.student_id = #{query.studentId} LEFT JOIN lesson_teacher lt ON l.id = lt.lesson_id LEFT JOIN staff s ON lt.teacher_id = s.id left join class c on c.id = ls.class_id left join classroom as cr on c.classroom_id = cr.id
and l.start_time >= #{query.beginTime}
and l.close_time <= #{query.endTime}
